pub fn printResult(result: TestResult) void {
    const status_str: []const u8 = switch (result.status) { .pass => "PASS", .fail => "FAIL", .skip => "SKIP" };
    std.debug.print("TEST {s} ... {s}", .{ result.name, .status_str = status_str });
    if (result.error_msg) |msg| {
        std.debug.print(" ({s})", .{ .msg = msg });
    }
    std.debug.print("\n", .{  });
}

pub fn printSummary(results: []const TestResult) void {
    var passed: usize = 0;
    var failed: usize = 0;
    var skipped: usize = 0;
    for (results) |*r| {
        switch (r.status) {
            .pass => {
                passed += 1;
            },
            .fail => {
                failed += 1;
            },
            .skip => {
                skipped += 1;
            },
        }
    }
    const total = passed + failed;
    std.debug.print("\n{d}/{d} tests passed", .{ .passed = passed, .total = total });
    if (skipped > 0) {
        std.debug.print(" ({d} skipped)", .{ .skipped = skipped });
    }
    std.debug.print("\n", .{  });
}
